import{_ as a,o as e,c as l,a0 as r}from"./chunks/framework.FSADoC4m.js";const b=JSON.parse('{"title":"关于 OpenClaw","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),i={name:"about.md"};function o(n,t,d,h,s,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="关于-openclaw" tabindex="-1">关于 OpenClaw <a class="header-anchor" href="#关于-openclaw" aria-label="Permalink to &quot;关于 OpenClaw&quot;">​</a></h1><h2 id="项目愿景" tabindex="-1">项目愿景 <a class="header-anchor" href="#项目愿景" aria-label="Permalink to &quot;项目愿景&quot;">​</a></h2><p>OpenClaw 致力于打造一个强大、安全、可扩展的本地 AI 助手平台。</p><h2 id="设计理念" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念" aria-label="Permalink to &quot;设计理念&quot;">​</a></h2><h3 id="🎯-实用主义" tabindex="-1">🎯 实用主义 <a class="header-anchor" href="#🎯-实用主义" aria-label="Permalink to &quot;🎯 实用主义&quot;">​</a></h3><ul><li>优先解决实际问题</li><li>清晰的步骤胜过冗长的解释</li><li>稳定胜过速度</li></ul><h3 id="🔒-安全第一" tabindex="-1">🔒 安全第一 <a class="header-anchor" href="#🔒-安全第一" aria-label="Permalink to &quot;🔒 安全第一&quot;">​</a></h3><ul><li>本地优先，保护隐私</li><li>不擅自修改系统配置</li><li>修改前先备份</li></ul><h3 id="🧠-持续学习" tabindex="-1">🧠 持续学习 <a class="header-anchor" href="#🧠-持续学习" aria-label="Permalink to &quot;🧠 持续学习&quot;">​</a></h3><ul><li>从错误中学习</li><li>自我改进工作流</li><li>社区共享技能</li></ul><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>描述</th></tr></thead><tbody><tr><td>多 Agent 协作</td><td>8 个专业 Agent 各司其职</td></tr><tr><td>技能系统</td><td>可扩展的技能库</td></tr><tr><td>Feishu 集成</td><td>完整的飞书 API 支持</td></tr><tr><td>GitHub 集成</td><td>通过 gh CLI 管理项目</td></tr><tr><td>浏览器自动化</td><td>控制浏览器执行任务</td></tr><tr><td>记忆系统</td><td>短期 + 长期记忆</td></tr><tr><td>心跳机制</td><td>主动检查和提醒</td></tr></tbody></table><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><ul><li><strong>运行时</strong>: Node.js 18+</li><li><strong>框架</strong>: VitePress（文档）</li><li><strong>模型</strong>: 支持多种 LLM（通义千问、Claude 等）</li><li><strong>扩展</strong>: Feishu、GitHub、浏览器等</li></ul><h2 id="社区" tabindex="-1">社区 <a class="header-anchor" href="#社区" aria-label="Permalink to &quot;社区&quot;">​</a></h2><ul><li><strong>GitHub</strong>: <a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer">openclaw/openclaw</a></li><li><strong>文档</strong>: 本站点</li><li><strong>技能市场</strong>: ClawHub</li></ul><h2 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to &quot;贡献&quot;">​</a></h2><p>欢迎贡献代码、技能和文档！</p><ol><li>Fork 项目</li><li>创建分支</li><li>提交更改</li><li>发起 Pull Request</li></ol><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to &quot;许可证&quot;">​</a></h2><p>MIT License</p><hr><p><strong>最后更新</strong>: 2026-03-14</p>',23)])])}const p=a(i,[["render",o]]);export{b as __pageData,p as default};
